package com.oyuki.kyc.controller; import com.oyuki.kyc.entity.KycSubmission; import com.oyuki.kyc.enums.KycStatus; import com.oyuki.kyc.repository.KycSubmissionRepository; import com.oyuki.user.repository.UserRepository; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import java.time.LocalDateTime; import java.util.*; @RestController @RequestMapping("/api/kyc") public class KycController { private final KycSubmissionRepository repo;private final UserRepository users;public KycController(KycSubmissionRepository r,UserRepository u){repo=r;users=u;} @PostMapping public Map<String,Object> submit(Authentication a,@RequestBody Map<String,String>b){Long id=(Long)a.getPrincipal();KycSubmission k=repo.findByUser_Id(id).orElseGet(()->KycSubmission.builder().user(users.findById(id).orElseThrow()).build());k.setIdType(b.get("idType"));k.setIdNumber(b.get("idNumber"));k.setDocumentUrl(b.get("documentUrl"));k.setSelfieUrl(b.get("selfieUrl"));k.setStatus(KycStatus.PENDING);return map(repo.save(k));} @GetMapping("/my") public Map<String,Object> mine(Authentication a){return repo.findByUser_Id((Long)a.getPrincipal()).map(this::map).orElse(Map.of("status","NOT_SUBMITTED"));} @GetMapping("/admin") public List<Map<String,Object>> all(){return repo.findAllByOrderBySubmittedAtDesc().stream().map(this::map).toList();} @PatchMapping("/admin/{id}") public Map<String,Object> review(@PathVariable Long id,@RequestBody Map<String,String>b){KycSubmission k=repo.findById(id).orElseThrow();k.setStatus(KycStatus.valueOf(b.get("status")));k.setReviewNote(b.get("reviewNote"));k.setReviewedAt(LocalDateTime.now());return map(repo.save(k));} private Map<String,Object> map(KycSubmission k){Map<String,Object>m=new LinkedHashMap<>();m.put("id",k.getId());m.put("userId",k.getUser().getId());m.put("name",k.getUser().getFullName());m.put("role",k.getUser().getRole());m.put("idType",k.getIdType());m.put("idNumber",k.getIdNumber());m.put("documentUrl",k.getDocumentUrl());m.put("selfieUrl",k.getSelfieUrl());m.put("status",k.getStatus());m.put("reviewNote",k.getReviewNote());m.put("submittedAt",k.getSubmittedAt());return m;} }